actions.script:
// ---- API-key extraction (fail-closed) -------------------------------------------------
// This realm is API-key ONLY. We deliberately do NOT consult ec.user / login_key here, so a
// request authenticated only by a Moqui session (no API key) is rejected below.
String apiKey = null
if (ec.web != null && ec.web.request != null) {
    String authz = ec.web.request.getHeader("Authorization")
    if (authz != null && authz.regionMatches(true, 0, "Bearer ", 0, 7)) {
        apiKey = authz.substring(7).trim()
    }
    if (apiKey == null || apiKey.isEmpty()) {
        String alt = ec.web.request.getHeader("X-Darpan-Gql-Key")
        if (alt != null) apiKey = alt.trim()
    }
}
if (apiKey == null || apiKey.isEmpty()) {
    // No web context or no key present -> 401-style auth error, query does NOT run.
    data = null
    errors = [[message: "missing API key", extensions: [code: "UNAUTHENTICATED"]]]
    extensions = [:]
    return
}

if (resolveOut == null || resolveOut.valid != true) {
    // Invalid/expired/disabled key -> auth error, query does NOT run. Clear any error the
    // resolve call pushed so the response is the single generic message.
    ec.message.clearErrors()
    data = null
    errors = [[message: "invalid API key", extensions: [code: "UNAUTHENTICATED"]]]
    extensions = [:]
    return
}
// Valid: run with the key's FIXED tenant + profile (never the session path).
def result = new org.moqui.gql.GqlEngine(ec).execute(query, (Map) variables, operationName,
        [scopeTenantId: resolveOut.companyUserGroupId, profileId: resolveOut.profileId,
         callerId: resolveOut.apiKeyId])
data = result.data
errors = result.errors
extensions = result.extensions
